// Inject PowerPlug brand values into generated HTML
const brand = $('Set PowerPlug Brand Context').first().json;
let html = $input.first().json.html || $input.first().json.content || '';

// CRITICAL BRAND SAFETY CHECKS
// 1. Replace any wrong CTA URLs
html = html.replace(/href="https:\/\/www\.sentice\.com\/[^"]*"/g, `href="${brand.cta_url}"`);
html = html.replace(/href="https:\/\/sentice\.com\/[^"]*"/g, `href="${brand.cta_url}"`);

// 2. Replace any wrong author images
html = html.replace(/src="[^"]*sentice[^"]*"/gi, `src="${brand.logo_colored}"`);
html = html.replace(/alt="Sentice[^"]*"/gi, `alt="${brand.brand_name}"`);

// 3. Replace wrong author name
html = html.replace(/Sentice Editorial Team/g, brand.author_name);
html = html.replace(/Sentice Team/g, brand.author_name);

// 4. Validate CTA URL presence
if (!html.includes(brand.cta_url)) {
  console.warn('WARNING: No CTA URL found in generated HTML');
}

// 5. Validate logo presence
if (!html.includes('powerplug-logo')) {
  console.warn('WARNING: PowerPlug logo not found in generated HTML');
}

return [{ json: { html, brand_validated: true, timestamp: new Date().toISOString() } }];

const html = $input.first().json.html;
const checks = {
  no_sentice_links: !html.includes('sentice.com/contact'),
  no_sentice_logo: !html.includes('sentice-author-logo'),
  has_powerplug_logo: html.includes('powerplug-logo'),
  has_correct_cta: html.includes('powerplug.ai/contact-us'),
  has_hero: html.includes('sa-hero-wrap'),
  has_toc: html.includes('sa-toc'),
  has_faq: html.includes('faq'),
  has_author: html.includes('PowerPlug Editorial Team'),
  has_trust_bar: html.includes('sa-trust-bar') || html.includes('Clalit')
};

const passed = Object.values(checks).filter(Boolean).length;
const total = Object.keys(checks).length;
const allPassed = passed === total;

if (!allPassed) {
  console.error('BRAND VALIDATION FAILED:', JSON.stringify(checks, null, 2));
}

return [{ json: { ...($input.first().json), validation: checks, validation_passed: allPassed, score: `${passed}/${total}` } }];
